STRINGS.CHARACTER_ABOUTME = STRINGS.CHARACTER_ABOUTME or {}
STRINGS.CHARACTER_ABOUTME.walter = "Walter tuhaf ama neşeli bir çocuktur, tehlike değerlendirme yeteneği arzu edilen seviyede değildir."
STRINGS.CHARACTER_ABOUTME.wanda = "Wanda geleceğinden kaçmak için hiçbir şeyden çekinmeyen yetenekli bir saatçidir."
STRINGS.CHARACTER_ABOUTME.warly = "Warly için yemek pişirmek, sevdiklerine olan sevgi ve minnettarlığını ifade ettiği bir dildir."
STRINGS.CHARACTER_ABOUTME.wathgrithr = "Wigfrid'in başrol oynamadan önceki kimliği zamanda kaybolmuş, method oyunculuğun gücüne yenilmiştir."
STRINGS.CHARACTER_ABOUTME.waxwell = "Eskiden Kabus Kralı olan Maxwell, son zamanlarda kendini sıradan halkın arasındaki hayatla yeniden tanıştırıyor."
STRINGS.CHARACTER_ABOUTME.webber = "Webber tüm arkadaşlarını, insan ya da başka türlü olsun, derinden önemseyen nazik genç bir canavardır."
STRINGS.CHARACTER_ABOUTME.wendy = "Wendy ölümü bile aşan güçlü bir kardeş bağına sahip melankolik genç bir hanımdır."
STRINGS.CHARACTER_ABOUTME.wes = "Wes çok düşünceli ama az sözlü bir mimdır."
STRINGS.CHARACTER_ABOUTME.wickerbottom = "Meraklı zihni ve sert tavrıyla Wickerbottom, yaşam boyu bilgi arayışında gelişir."
STRINGS.CHARACTER_ABOUTME.willow = "Willow ateşe olan düşkünlüğü onu sık sık belaya sokan samimi bir kadındır."
STRINGS.CHARACTER_ABOUTME.wilson = "Wilson özünde gerçek bir bilim insanıdır. Bilinmeyenin çağrısına direnmek onun doğasında yoktur."
STRINGS.CHARACTER_ABOUTME.winona = "Winona gürültücü tavrı ve mekanik şeylere olan sevgisiyle eski montaj hattı işçisidir."
STRINGS.CHARACTER_ABOUTME.wolfgang = "Wolfgang sayısız fobiyle dolu kalbi olan sevimli, kaslı bir devdir."
STRINGS.CHARACTER_ABOUTME.wonkey = "Bu zavallı ruh korkunç Ay Rıhtımı korsanlarının lanetine kurban gitmiştir."
STRINGS.CHARACTER_ABOUTME.woodie = "Huysuz, sakallı bir ormancı olan Woodie'nin doğaya, ekose desene ve güvenilir baltası Lucy'ye karşı zaafı vardır."
STRINGS.CHARACTER_ABOUTME.wormwood = "Ay büyüsüyle bilinç kazanmış asma karışımı olan Wormwood, nihayet ait olabilmek için arkadaş arar."
STRINGS.CHARACTER_ABOUTME.wortox = "Wortox neşesi derin bir suçluluk kuyusunu gizleyen yaramaz bir şeytandır. Zamanında birçok ruh almıştır."
STRINGS.CHARACTER_ABOUTME.wurt = "Wurt ufkunu genişletmeye çalışan meraklı genç bir Merm'dir... bu ufuklar Domuz bölgesine uzanmadığı sürece."
STRINGS.CHARACTER_ABOUTME.wx78 = "WX'in katı doğasının hassas bir iç ruh gizlediği varsayılabilir. Bu varsayım yanlış olurdu."
STRINGS.CHARACTER_DESCRIPTIONS = STRINGS.CHARACTER_DESCRIPTIONS or {}
STRINGS.CHARACTER_DESCRIPTIONS.random = "O şapkanın altında herhangi biri olabilir"
STRINGS.CHARACTER_DESCRIPTIONS.walter = "*Yaralanmak dışında hiçbir şeyden korkmaz \n*Sapanla iyidir \n*Dört bacaklı arkadaşı var \n*Arılara alerjisi var \n*Modayla ilgilenmez"
STRINGS.CHARACTER_DESCRIPTIONS.wanda = "*Mükemmel zaman yönetimi becerileri var \n*Sadece hissettiği kadar yaşlı \n*Zamanla sürekli yarış halinde"
STRINGS.CHARACTER_DESCRIPTIONS.warly = "*Kendi özel taşınabilir mutfak eşyası serisi var \n*İşleri baharatlayabilir \n*Doyumsuz iştahı var \n*Sadece gurme yemek yer"
STRINGS.CHARACTER_DESCRIPTIONS.wathgrithr = "*Savaşta üstün \n*Düşen düşmanların gücünü emer \n*Baskı altında iyi performans gösterir \n*Sadece et yer"
STRINGS.CHARACTER_DESCRIPTIONS.waxwell = "*Şık ama zayıf \n*Zihnini parçalara bölebilir \n*Gölgeli ekipmanlardan güç alır \n*Bir zamanlar dünyanın kralıydı"
STRINGS.CHARACTER_DESCRIPTIONS.webber = "*Bir canavar \n*Örümceklerle arkadaş olabilir \n*İpeksi pürüzsüz sakal uzatır"
STRINGS.CHARACTER_DESCRIPTIONS.wendy = "*İkiz kız kardeşinin hayaleti tarafından takip ediliyor \n*Karanlıkta rahat hissediyor \n*Ektoherbololoji ile uğraşıyor \n*Çok sert vurmaz"
STRINGS.CHARACTER_DESCRIPTIONS.wes = "*Konuşamaz \n*Balonculuk yapar \n*Yetenekli bir savaşçı ya da işçi değil \n*Hayatta kalmakta zorlanır"
STRINGS.CHARACTER_DESCRIPTIONS.wickerbottom = "*Birçok şey bilir \n*Kendi kitaplarını yayınlar \n*Uykusuzluk çeker \n*Hassas bir midesi var"
STRINGS.CHARACTER_DESCRIPTIONS.willow = "*Ateşe düşkün ama soğuktan nefret eder \n*Sevimli ayısı Bernie tarafından korunur\n*Güvenilir bir çakmağı var"
STRINGS.CHARACTER_DESCRIPTIONS.wilson = "\n*Muhteşem bir sakal uzatır"
STRINGS.CHARACTER_DESCRIPTIONS.winona = "*Yetenekli bir inşaatçı\n*Karanlıktan bir bedava vuruş alır\n*Kendi aletlerini icat eder"
STRINGS.CHARACTER_DESCRIPTIONS.wolfgang = "*Güçlü olmak için sıkı çalışır \n*Düzenli egzersiz yapmadan zayıflar \n*Ağır nesneleri kolayca taşır \n*Canavarlardan ve karanlıktan korkar"
STRINGS.CHARACTER_DESCRIPTIONS.wonkey = "*Kim olduklarsa, artık bir maymun"
STRINGS.CHARACTER_DESCRIPTIONS.woodie = "*Güzel bir baltası var... \n*Ve ormanla savaş halinde \n*Kunduz Adam lanetinden muzdarip! \n*Ayrıca Geyik Adam ve Kaz Adam... \n*Bereketli hasatlar için minnettar"
STRINGS.CHARACTER_DESCRIPTIONS.woodie_canada = "*Güzel bir baltası var... \n*Ve ormanla savaş halinde \n*Kunduz Adam lanetinden muzdarip! \n*Ayrıca Geyik Adam ve Kaz Adam... \n*Şükran Günü'nü doğru zamanda kutlar"
STRINGS.CHARACTER_DESCRIPTIONS.woodie_us = "*Güzel bir baltası var... \n*Ve ormanla savaş halinde \n*Kunduz Adam lanetinden muzdarip! \n*Ayrıca Geyik Adam ve Kaz Adam... \n*Şükran Günü'nü çok erken kutlar"
STRINGS.CHARACTER_DESCRIPTIONS.wormwood = "*Bitkiler onunla ilişki kurar \n*Bitkiler öldürüldüğünde üzülür \n*Yeşil parmağı var \n*Yemek midesini doyurur ama kalbini değil"
STRINGS.CHARACTER_DESCRIPTIONS.wortox = "*Bir şeytan \n*Zaman ve uzayda sıçrayabilir \n*Fiziksel yiyeceklerden daha az beslenme alır"
STRINGS.CHARACTER_DESCRIPTIONS.wurt = "*Bataklıkta evinde hisseder \n*Balık-İnsan türü için büyük planları var \n*Vejetaryen"
STRINGS.CHARACTER_DESCRIPTIONS.wx78 = "*Devrelerle yükseltilebilir \n*Yemek konusunda seçici değil \n*Şimşekle şarj olur ama sudan zarar görür"
