STRINGS.SCRAPBOOK.SPECIALINFO.ANCIENTTREE_SEED = "Büyüme koşulları konusunda çok seçici olan egzotik bir tohum. Her şeyin bir zamanı ve yeri vardır..."
STRINGS.SCRAPBOOK.SPECIALINFO.ANIMALTRACK = "Bir yere doğru yürüyen bir hayvanın ayak izi."
STRINGS.SCRAPBOOK.SPECIALINFO.ANTLIONHAT = "Taşıyıcı üzerinde durduğu çimi kazacak ve çim eşyalarıyla yüklendiğinde çim yerleştirecek."
