STRINGS.SCRAPBOOK.SPECIALINFO.ARCHIVESECURITYDESK = "Güçlendirildiğinde ve yakınından bir hayatta kalan geçtiğinde, bu cihaz Arşiv Labirenti'nde dolaşmaya başlayan bir enerji topu salacak."
STRINGS.SCRAPBOOK.SPECIALINFO.ARCHIVESWITCH = "Bir ampulü değiştirmek kaç Hayatta Kalan gerektirir?"
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORBONE = "Her 5 saniyede bir, gelen bir darbe tamamen görmezden gelinecek."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORBRAMBLE = "Bu dikenli kabuk saldırıya uğradığında hasar verir."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORDRAGONFLY = "Ejder Sineği pullarıyla sarılmış, seni ateşe karşı bağışık yapar."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORDREADSTONE = "Bu zırh kendini yavaşça tamir eder."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORLUNARPLANT = "Hasarı düşmanlara geri yansıtır ve Gölge Hizalı olanlara daha fazla."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORMARBLE = "Bu zırh dayanıklı ama ağır, kullanıcısını yavaşlatır."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORSANITY = "Hasarı engeller ama kullanıcısını delirtme gibi kötü bir alışkanlığı var."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORSLURPER = "Zamanla akıl sağlığı yeniler ve açlık azalmasını %40 yavaşlatır."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORSNURTLESHELL = "Herhangi bir saldırıdan kurtulmak için bu sert kabuğun içine saklanabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMORWAGPUNK = "\"Pekala, Oldukça Güzel Zeki Sistem.\" Hesaplama için karmaşık dişli ve devre düzeneği kullanır.\n\nBir hedef seçildikten sonra, menzilde kaldığı sürece W.A.R.B.I.S. hedefle savaşmak için optimal performansı hesaplamaya başlar.\n\nZırh hedefi analiz ederken kullanıcının hızını artırır, %30 hız artışında son bulur.\n\nW.A.R.B.I.S. başlığıyla birleştirildiğinde, ikisi birkaç anlığına hedef bilgilerini paylaşarak senkronize olur."
STRINGS.SCRAPBOOK.SPECIALINFO.ARMOR_CARROTLURE = "Tavşan Adamları onun büyüleyici kokusuna çekilir, et kokusunu maskeleyecek kadar güçlü."
STRINGS.SCRAPBOOK.SPECIALINFO.ATRIUMGATE = "Tabanında boş yuva olan kırık taş halka."
STRINGS.SCRAPBOOK.SPECIALINFO.ATRIUMRUBBLE = "İncelenebilir yazıları olan çökmekte olan nesne."
STRINGS.SCRAPBOOK.SPECIALINFO.BALATRO_MACHINE = "Jimbo adında biri seninle kart oyunu oynamanı istiyor.\n\nBaşlamak için üç Joker'den birini seçmelisin. Her birinin sana küçük bir avantaj sağlamanın farklı yolu var.\n\nİkinci olarak, Poker oyna. Kartları atıp yenileriyle değiştirebilirsin. Bunu iki kez yapabilirsin.\n\nSonra elin değerlendirilecek. Kartlarının değerine göre jeton alacaksın. Elinin kalitesine göre çarpan alacaksın. Jetonların çarpı Çarpanın puanın olur. Olabildiğince çok puan al. Jimbo zamanın için sana bir şey verebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.BALLOONHAT = "Yıldırım çarpmasından korur."
STRINGS.SCRAPBOOK.SPECIALINFO.BALLOONVEST = "Kullanıcı kıyıya vurduğunda boğulma hasarı almaz."
STRINGS.SCRAPBOOK.SPECIALINFO.BANDAGE = "30 Can iyileştirir."
STRINGS.SCRAPBOOK.SPECIALINFO.BANDAGE_BUTTERFLYWINGS = "24 sağlık iyileştirir.\n\nWalter tarafından kullanılırsa ve Saha Sıhhiyecisi becerisini öğrenmişse, ek 12 sağlık iyileştirir ve ayrıca 10 akıl sağlığı yeniler."
STRINGS.SCRAPBOOK.SPECIALINFO.BATBAT = "Her saldırı canlı hedeflerden 6.8 Can çeker.\n\nKullanıcı tam sağlıkta değilse, ayrıca 3.4 Akıl Sağlığı da çeker."
STRINGS.SCRAPBOOK.SPECIALINFO.BATHBOMB = "İçine atıldığında kaplıcayı sıcak, buğulu ve cam gibi yapar."
STRINGS.SCRAPBOOK.SPECIALINFO.BATNOSEHAT = "Her 5 saniyede 3.9 Açlık yeniler."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_CONTAINER = "Savaş Şarkıları ve Savaş İğneleri tutabilen 8 slotlu taşınabilir konteyner."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_DURABILITY = "Dinlerken silahlarınızın aşınmasını %25 azaltır.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_FIRERESISTANCE = "Wigfrid ve yakındaki müttefikler ateş hasarı almaz.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_HEALTHGAIN = "Wigfrid ve yakındaki müttefikler savaşırken iyileşir. Wigfrid biraz daha fazla iyileşir.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_INSTANT_PANIC = "Yakındaki düşmanları paniğe sevk eder.\n\nBu bir Savaş İğnesidir çünkü anında tamamlanır."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_INSTANT_REVIVE = "Yakındaki 2 müttefik oyuncuyu diriltir.\n\nBu bir Savaş İğnesidir çünkü anında tamamlanır."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_INSTANT_TAUNT = "Yakındaki düşmanların dikkatini çeker.\n\nBu bir Savaş İğnesidir çünkü anında tamamlanır."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_LUNARALIGNED = "Wigfrid ve yakındaki müttefikler Ay Hizalı düşmanlardan %10 daha az hasar alır ve Gölge Hizalı düşmanlara %5 bonus hasar verir.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_SANITYAURA = "Bu güzel şarkıyı dinlerken korkunç yaratıklar yarı yarıya daha az korkutucu görünür.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_SANITYGAIN = "Wigfrid ve yakındaki müttefikler savaşırken akıl sağlığı kazanır.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BATTLESONG_SHADOWALIGNED = "Wigfrid ve yakındaki müttefikler Gölge Hizalı düşmanlardan %10 daha az hasar alır ve Ay Hizalı düşmanlara %5 bonus hasar verir.\n\nBu bir Savaş Şarkısıdır. Wigfrid faydasını görmek için şarkı söylemeye devam etmelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.BEARGERFUR_SACK = "Hazırlanmış yiyecek tutabilen 6 slotlu taşınabilir konteyner.\n\nİçinde saklanan yiyecek uzun süre korunur."
STRINGS.SCRAPBOOK.SPECIALINFO.BEARGERVEST = "Takıldığında açlık oranı %25 yavaşlar."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEBOX = "Arı kovanının etrafında 6 veya daha fazla çiçek varsa, arılar kovanın içinde bal üretir."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEFALO = "Agresif çiftleşme mevsiminden sakının.\n\nBu canavarlardan birini besleyip bakın, belki de eyer takabilirsiniz."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEFALOFEED = "Beefalo için atıştırmalık."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEFALOGROOMER = "Hayatta kalan bağlı bir beefalo'yu bu tımar makinesine bağlayabilir ve sonra Beefalo'nun kıyafetini ekleyebilir veya değiştirebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEFALOHAT = "Taşıyıcıyı kızgınlık dönemindeki Beefalo'lara karşı dostane yapar."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEFALOTREAT = "Beefalo için atıştırmalık."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEF_BELL = "Aynı anda bir Beefalo ile isim ver ve bağ kur. Bağlı Beefalo taşıyıcıyı takip eder, mağaralara ve çevrimdışı durumda bile."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEHAT = "Bu şapkanın sunduğu koruma sadece Arılar ve Arı benzeri yaratıklara karşı işe yarar."
STRINGS.SCRAPBOOK.SPECIALINFO.BEEQUEENHIVE = "Bu devasa ve son derece dürtüklenebilir arı kovanı tatlı bal ve diğer sürprizlerle dolu."
STRINGS.SCRAPBOOK.SPECIALINFO.BEESWAX_SPRAY = "Bir bitkinin aşamasını dondur. Bu onu verimsiz yapar ama aynı zamanda parazitler için çekici olmaz."
STRINGS.SCRAPBOOK.SPECIALINFO.BERNIE = "Willow'un aklı deliliğe yaklaştığında güçlü bir arkadaş."
STRINGS.SCRAPBOOK.SPECIALINFO.BIRDCAGE = "Bu kafese bir kuş konabilir.\n\nKuşu beslemeyi unutma.\n\nKuş meyve veya sebze ile beslenirse, o mahsullerden tohum çıkarır.\n\nKuş et ile beslenirse, yumurta bırakabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.BLUEAMULET = "Kullanıcıyı soğutarak akıl sağlığını artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.BLUEPRINT = "Sana belirli bir şeyin nasıl yapılacağını öğretir."
STRINGS.SCRAPBOOK.SPECIALINFO.BLUESTAFF = "Dondurucu mermiler atar."
STRINGS.SCRAPBOOK.SPECIALINFO.BOATCANNON = "Top mermisi ile doldurulabilir.\n\nDoldurulduktan sonra nişan alınarak ateşlenebilir. Ateşlemeden önce farklı yanlarından yanına durarak yön değiştirilebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.BOATMAGNET = "Bu yapı önce bir Nautopilot İşareti ile eşleştirilmelidir.\n\nEşleştirildikten sonra kendini işarete doğru çeker.\n\nBir teknedeyse, teknenin o yöndeki hızını artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.BOATPATCH = "Teknelerdeki sızıntıları tıkar."
STRINGS.SCRAPBOOK.SPECIALINFO.BOATPATCH_KELP = "Sızıntılar için geçici çözüm. Sızıntı mı var? Yosun yaması kullan... sonra bir tane daha... ve bir tane daha..."
STRINGS.SCRAPBOOK.SPECIALINFO.BOAT_ANCIENT = "Dahili 16 yuvalı konteyner ile güçlendirilmiş tekne. Eskiden böyle yapmazlardı."
STRINGS.SCRAPBOOK.SPECIALINFO.BOAT_BUMPER_CRABKING = "Karaya çarparken hasar almayan kaya benzeri tampon. Al sana, kara!"
