STRINGS.SCRAPBOOK.SPECIALINFO.BOAT_BUMPER_SHELL = "Takıldığı teknenin çarpışma hasarını emer. Kırık Kabuklar ile tamir edilebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOKSTATION = "Kitaplar ve papirüs için 20 yuvalı konteyner.\n\nİçindeki kitaplar her 30 saniyede 1 dayanıklılık kazanır, Wickerbottom yakındaysa iki katı.\n\nAyrıca kütüphane Simya Motoru gibi çalışır ve yakındaki hayatta kalanlara yapabilecekleri yeni şeyler sunar."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_BEES = "2 Homurdanan Arı takipçisi çağırır. Aynı anda maksimum 16."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_BIRDS = "Yakına inmesi için 20'ye kadar kuş çağır."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_BRIMSTONE = "Düzinelerce kontrolsüz yıldırım düşür."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_FIRE = "Yakındaki tüm yanan ve için için yanan ateşleri söndürür ve o enerjiyle dolu bir Ateşli Kalem yaratır veya şarj eder."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_FISH = "Yakında bir Okyanus Balığı sürüsü çağırır."
