STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_MOON = "Mevcut ay evresini dolunaya ayarlar."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_RAIN = "Yağmur yağıyorsa, yağmur durur. Yağmur yağmıyorsa, yağmur başlar ve yakındaki çiftlik toprağını sular."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_RESEARCH_STATION = "Yakındaki hayatta kalanlara bir işçilik şarjı verir. Her şarj, bir sonraki eşyayı normalden bir teknoloji seviyesi daha yüksek işlemelerine izin verir."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_SILVICULTURE = "Yakındaki çimen, fidan ve ağaçları büyütür, ancak çimen daha erken gübrelenmeye ihtiyaç duyar."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_SLEEP = "Yakındaki yaratıkları uyutur."
