STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_TENTACLES = "Yakında bazı düşmanca Çadırlar çağırır."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOK_WEB = "Yerde üzerinde seyahat eden yaratıkları yavaşlatan birkaç çim değerinde Örümcek Ağı yaratır.\n\n2 dakika sonra kaybolur."
STRINGS.SCRAPBOOK.SPECIALINFO.BOOMERANG = "Fırlattıktan sonra yakalamalısın."
