STRINGS.SCRAPBOOK.SPECIALINFO.BRUSH = "Beefalo Yünü toplamak için Beefalo'larda kullanılabilir.\n\nBeefalo İtaatini %40 artırır ve günde bir kez Beefalo evcilleştirmesini %1.6 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.BUGNET = "Küçük uçan şeyleri yakala ve onları veya ganimetlerini envanterine koy."
