STRINGS.SCRAPBOOK.SPECIALINFO.BUSHHAT = "Taşıyıcı çalının altına saklanabilir ve yaratıklar hayatta kalanın saklandığını görmedikleri sürece saldırmayacaklardır."
STRINGS.SCRAPBOOK.SPECIALINFO.CAMPFIRE = "Yakıtlıyken ışık ve ısı üretir.\n\nAyrıca yiyecekleri pişmiş hallerine dönüştürebilir.\n\nYakıtı bittiğinde kaldırılır."
