STRINGS.SCRAPBOOK.SPECIALINFO.CARTOGRAPHYDESK = "Hayatta kalanların harita bilgilerini değiştirmek için Harita Tomarları üretmesini sağlar.\n\nÇizimler, Eskizler, Kostüm Kalıpları, Anı Defteri Sayfaları, İlanlar veya Tarif Kartlarını bunun üzerinde kullanmak onları boş Papirüse dönüştürür."
STRINGS.SCRAPBOOK.SPECIALINFO.CATCOONDEN = "Bir Kedirakunun ini ve taşıdıkları eşyaları sakladıkları yer.\n\nO eşyalar buradan alınabilir, ama Kedirakunun hoşuna gitmez."
STRINGS.SCRAPBOOK.SPECIALINFO.CAVE_VENT_MITE = "Fumarolün döngüsü Jeotermitle başlar."
