STRINGS.SCRAPBOOK.SPECIALINFO.CHARLIE_STAGE_POST = "Constant Kraliçesi tarafından size nezaketle bahşedilen bir hediye, zavallı, boş küçük hayatlarınızı zenginleştirmek için. Kostümler ve senaryo hazırlayacak kadar bile nazikti!"
STRINGS.SCRAPBOOK.SPECIALINFO.CHESTER = "Eşyalar Chester'da tıpkı bir sandık gibi saklanabilir."
