STRINGS.SCRAPBOOK.SPECIALINFO.COOKBOOK = "Pişirilen ve/veya yenen tüm yiyeceklerin ve bunları pişirmek için kullanılan malzemelerin kaydı."
STRINGS.SCRAPBOOK.SPECIALINFO.COOLANT = "Kavrayış özü... Güç kaynağı... ...Köpürüyor."
