STRINGS.SCRAPBOOK.SPECIALINFO.CRAFTINGSTATION = "Bu cihazın yanında durmak hayatta kalana yapabileceği yeni şeyler sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.CRATEREDMOONROCK = "Mücevher şeklinde yuva içerir."
