STRINGS.SCRAPBOOK.SPECIALINFO.OFFERING_POT = "Craftsmerm Evleri, Merm Kalelerinde ve Sızdıran Kulübelerde Merm'lerin yeniden doğuşunu hızlandırır.\n\nYakındaki Merm'leri çağırıp yosunu yemeye ve onları çağıran Merm'i takip etmeye ikna etmek için kullanılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.OFFERING_POT_UPGRADED = "Craftsmerm Evleri, Merm Kalelerinde ve Sızdıran Kulübelerde Merm'lerin yeniden doğuşunu hızlandırır.\n\nYakındaki Merm'leri çağırıp yosunu yemeye ve onları çağıran Merm'i takip etmeye ikna etmek için kullanılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.ONEMANBAND = "Tek Kişilik Bando'yu giymek akıl sağlığını düşüren bir deneyimdir, ancak yakındaki domuz adamları ve tavşan adamları takipçilere dönüştürür."
