STRINGS.SCRAPBOOK.SPECIALINFO.SHELLCLUSTER = "Kabuk Çanları için kazılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SHIELDOFTERROR = "Yemek vererek tamir edilebilir."
