STRINGS.SCRAPBOOK.SPECIALINFO.SISTURN = "Yaprak tutabilen 4 slotlu konteyner.\n\nYapraklarla dolu olduğunda yakındaki hayatta kalanların Akıl Sağlığını dakikada 25 artırır.\n\nAyrıca Abigail'in sağlığı 4 kat daha hızlı yenilenir.\n\nYapraklar çürüdüğünde konteynerden çürük olarak yere düşer."
STRINGS.SCRAPBOOK.SPECIALINFO.SKELETONHAT = "Bunu takmak seni anında delirtir; gölgeler bile seni tolere eder."
STRINGS.SCRAPBOOK.SPECIALINFO.SLEEPBOMB = "Fırlatıldığında yaratıkları uyutacak bulut oluşturur."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_CONTAINER = "Sapan Mermisi tutabilen 6 slotlu taşınabilir konteyner."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_DREADSTONE = "%50 ihtimalle çarpma anında kırılmaz."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_GELBLOB = "Hedefinize 60 saniye boyunca bir Icker damlası yapıştırır, onu büyük ölçüde yavaşlatır."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_GUNPOWDER = "Artan bir ihtimalle patlama tetikler, geniş bir alanda çifte hasar verir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_HONEY = "Yer hedeflerini 8 saniye yavaşlatır."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_HORRORFUEL = "Vurduğu yaratıklara Sürü Dehşeti zayıflatması uygular ve aralıklarla 10 düzlemsel hasar verir. Her hedefte en fazla 4 yığın birikebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_LUNARPLANTHUSK = "Çarpma anında hedefinize düzlemsel hasar veren bir Parlak Gölge Asması yaratma şansı vardır."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_MOONGLASS = "Hedefinin etrafında orta büyüklükte bir alanda hasar verir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_POOP = "Bazı hedeflerin sizinle ilgisini kaybetmesine neden olur."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_PUREBRILLIANCE = "Vurduğu yaratıklara 30 saniye süren Saf Parlaklık işareti uygular. Bu işaret düzlemsel saldırılarla tetiklenebilir ve vuruş başına ek 5 düzlemsel hasar verir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_SCRAPFEATHER = "Islak hedeflere daha fazla hasar veren elektriksel hasar verir. Ayrıca diğer mermilerden daha sık sersemletme tetikleyebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_SLOW = "Hedefinizi 30 saniye yavaşlatır, 3 kata kadar yığılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_STINGER = "Hedefinin etrafında küçük bir alanda hasar verir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTAMMO_THULECITE = "Çarpma anında hedefinize hasar veren bir Gölge Çadırı yaratma şansı vardır."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOTMODKIT = "Sapanınızı özelleştirmenizi sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_BAND_MIMIC = "Ne kadar uzağa ateş edebileceğinizi ve mühimmatınızın ne kadar hızlı gittiğini büyük ölçüde artırır. Bazen taklit versiyonunu fırlatarak mühimmat tasarrufu yapar."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_BAND_PIGSKIN = "Ne kadar uzağa ateş edebileceğinizi ve mühimmatınızın ne kadar hızlı gittiğini orta düzeyde artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_BAND_TENTACLE = "Ne kadar uzağa ateş edebileceğinizi ve mühimmatınızın ne kadar hızlı gittiğini büyük ölçüde artırır. Kalpsiz bir canavar tarafından ele geçirilebilir..."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_FRAME_BONE = "Sapanınıza yedek mühimmat yuvası ekler."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_FRAME_GEMS = "Sapanınıza özel mühimmat yuvası ekler, bu yuva mühimmatınızın sihirli etkilerini alan etkisine genişleten ikincil, alternatif Sapan saldırısı için kullanılır."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_FRAME_WAGPUNK = "Mühimmat yuvasını sınırsız yığın boyutuna genişletir ve %200'e kadar hasar vermek için basılı tutarak şarj edilebilen ikincil, alternatif Sapan saldırısı ekler."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_FRAME_WAGPUNK_0 = "İkincil, alternatif Sapan saldırısı ekler, basılı tutarak şarj edilebilir ve %200'e kadar hasar verebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_HANDLE_JELLY = "Atış hızını büyük ölçüde artırır ve Sapanın elinden kaymasını önler."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_HANDLE_SILK = "Atış hızını orta düzeyde artırır, sürekli ateş edersen daha da artar."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_HANDLE_STICKY = "Atış hızını orta düzeyde artırır ve Sapanın elinden kaymasını önler."
STRINGS.SCRAPBOOK.SPECIALINFO.SLINGSHOT_HANDLE_VOIDCLOTH = "Atış hızını büyük ölçüde artırır, sürekli ateş edersen daha da artar."
STRINGS.SCRAPBOOK.SPECIALINFO.SLURTLESLIME = "Yakıldığında 50 hasarla patlar. Ayrıca Fener ve Madenci Şapkası için de yakıt olur."
STRINGS.SCRAPBOOK.SPECIALINFO.SNOWMAN = "Yuvarla! Yığ! Çeşitli eşyalarla süsle!"
STRINGS.SCRAPBOOK.SPECIALINFO.SOILAMENDER = "Fermantasyon seviyesine göre toprağa 8-32 Büyüme Formülü besin maddesi ekler.\n\nAyrıca fermantasyon seviyesine göre Wormwood'un 1-4 dakika çiçek açmasını tetikler."
STRINGS.SCRAPBOOK.SPECIALINFO.SPEAR_WATHGRITHR_LIGHTNING = "Elektriksel hasar verir, ıslak hedeflere daha fazla hasar yapar."
STRINGS.SCRAPBOOK.SPECIALINFO.SPEAR_WATHGRITHR_LIGHTNING_CHARGED = "Elektriksel hasar verir, ıslak hedeflere daha fazla hasar yapar.\n\nTutulduğunda hareket hızını %20 artırır.\n\nSadece \"Elding Mızrağı Geliştirmesi II\" becerisine sahip Wigfrid'ler kuşanabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SPEEDYBALLOON = "Tutulduğunda hareket hızını %30 artırır, çürüdükçe %20'ye sonra %10'a düşer.\n\nTamamen çürümeden yere düşürülürse 1.5 saniye sonra havaya yükselir ve konumu tüm hayatta kalanlara mini haritada görünür."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICEPACK = "İçindeki eşyaların bozulmasını yavaşlatan 6 bölmeli konteyner."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICE_CHILI = "Taşınabilir Baharat İstasyonu kullanarak Tencere yemeklerine eklenebilir.\n\nAcı Biber Pul ile baharatlanmış yemek yiyen saldırılarına %20 hasar ekler.\n\nSüre 4 dakika.\n\nAyrıca 15 saniye boyunca sıcaklığı 15 derece yükseltir."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICE_GARLIC = "Taşınabilir Baharat İstasyonu kullanarak Tencere yemeklerine eklenebilir.\n\nSarımsak ile baharatlanmış yemek yiyen sağlığına aldığı hasarı %33 azaltır.\n\nSüre 4 dakika."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICE_SALT = "Taşınabilir Baharat İstasyonu kullanarak Tencere yemeklerine eklenebilir.\n\nBaharat Tuzu ile baharatlanmış yemek yiyen iyileştirme etkilerinden %25 daha fazla iyileşme kazanır.\n\nSüre 4 dakika."
STRINGS.SCRAPBOOK.SPECIALINFO.SPICE_SUGAR = "Taşınabilir Baharat İstasyonu kullanarak Tencere yemeklerine eklenebilir.\n\nBal Kristalleri ile baharatlanmış yemek yiyen Madencilik, Odun Kesme ve Çekiçleme hızını ikiye katlar.\n\nSüre 4 dakika."
STRINGS.SCRAPBOOK.SPECIALINFO.SPIDERDEN = "Yakınında yerde hayatta kalanları ve bazı yaratıkları yavaşlatan ağ yaması oluşturur.\n\nÇeşitli boyutlarda gelir ve örümcek nüfusuna uyacak şekilde büyür.\n\nWebber bunları İpek ile geliştirebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.SPIDERGLAND = "Hayatta kalanlarda veya yaratıklarda kullanıldığında 8 Can iyileştirir."
STRINGS.SCRAPBOOK.SPECIALINFO.SPIDERHAT = "Yakındaki 10'a kadar Örümcek taşıyıcıyı takip eder, ancak örümceklere saldıran yaratıklar taşıyıcıya da saldırır.\n\nÖrümcek Kraliçesi tarafından doğurulan Örümceklerde çalışmaz."
STRINGS.SCRAPBOOK.SPECIALINFO.SPIDERREPELLENT = "Webber tarafından kullanıldığında yakındaki saldırgan örümcekler pasif hale gelir ve Webber'ı takip eden örümcekleri serbest bırakır."
STRINGS.SCRAPBOOK.SPECIALINFO.SPIDERWHISTLE = "Webber düdüğü yakındaki örümcekleri ve örümcek yuvalarını uyandırmak için kullanabilir.\n\nYakındaki örümcekler hedeflerine saldırmayı bırakır ve yerdeki yiyecekleri geçici olarak görmezden gelir."
STRINGS.SCRAPBOOK.SPECIALINFO.SPIDER_HEALER = "Webber'ı 8 Can iyileştirir ve bir alandaki örümcekleri 80 Can iyileştirir."
STRINGS.SCRAPBOOK.SPECIALINFO.STAFFCOLDLIGHT = "Hayatta kalanları serinletir ve 2 gün boyunca ışık verir."
STRINGS.SCRAPBOOK.SPECIALINFO.STAFFLIGHT = "Süresi boyunca kamp ateşi gibi çalışır, ışık ve ısı yaratır ve yakındaki şeyleri tutuşturur. Yemek pişirmek için de kullanılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.STAFFTORNADO = "Rastgele hareket eden, yaratıklara zarar veren ve yapıları kıran bir kasırga fırlatır."
STRINGS.SCRAPBOOK.SPECIALINFO.STATUEGLOMMER = "Gündüz ayın ışığını yansıtan garip bir heykel."
STRINGS.SCRAPBOOK.SPECIALINFO.STEERINGWHEEL = "Bir tekneye yerleştirildiğinde, hayatta kalan onu teknenin yönünü döndürmek için kullanabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.STORAGE_ROBOT = "Eşyaları toplayıp konteynerlere düzenleyebilen bir otomat. Yanındaki bir konteynere bir eşya koy ve ne yapması gerektiğini bilecek!"
STRINGS.SCRAPBOOK.SPECIALINFO.STRAWROLL = "İçinde uyumak saniyede 0.66 Akıl Sağlığı ve 0.5 can yeniler, saniyede 1 Açlık harcar."
STRINGS.SCRAPBOOK.SPECIALINFO.SUPERTACKLECONTAINER = "Olta Takımı tutmak için 15 bölmeli konteyner."
STRINGS.SCRAPBOOK.SPECIALINFO.SUSPICIOUSMARBLE = "Kırık mermer heykel parçası."
STRINGS.SCRAPBOOK.SPECIALINFO.TABLEWINTERSFEAST = "Bu masaya sadece özel Kış Şöleni yemekleri konabilir.\n\nBu masadaki \"yemek\" \"yenildiğinde\" hayatta kalana Kış Neşesi etkisi verir.\n\nEtki hayatta kalanı saniyede 0.5 Can, dakikada 10 Akıl Sağlığı ve günde 75 Açlık iyileştirir ve normal açlık kaybını durdurur.\n\nEtkinin süresi şölenin ne kadar görkemli olduğuna bağlıdır. Birbirine bağlı daha fazla masa, birlikte şölen yapan daha fazla hayatta kalan ve çeşitli yemekler etkinin süresini artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.TACKLECONTAINER = "Olta Takımı tutmak için 6 bölmeli konteyner."
STRINGS.SCRAPBOOK.SPECIALINFO.TACKLESTATION = "Bu cihazın yanında durmak hayatta kalana üretebileceği yeni Yemler ve Şamandıralar sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.TELEBASE = "Bu cihazın aktif olması için 3 mor mücevher gerekir\n\nTeleportasyon Asası kullanan hayatta kalan en yakın aktif Teleportasyon Odağına ışınlanır ve mücevherleri tüketir."
STRINGS.SCRAPBOOK.SPECIALINFO.TENT = "Hayatta kalan çadırı Alacakaranlık veya Gece kullanabilir.\n\nHayatta kalan saniyede 2 Can ve saniyede 1 Akıl Sağlığı kazanır ama saniyede 0.33 Açlık tüketir. Ayrıca saniyede 1 Islaklık azaltır ve 40 dereceye kadar saniyede 1 derece sıcaklık artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.TENTACLEPILLARHOLE = "Başka bir yere giden tünele açılan delik."
STRINGS.SCRAPBOOK.SPECIALINFO.TERRARIUM = "Umarım kimse onu açmaz, ya da daha kötüsü, bozar."
STRINGS.SCRAPBOOK.SPECIALINFO.THULECITEBUGNET = "Küçük uçan şeyleri yakala ve onları ya da ganimetlerini envanterine koy."
STRINGS.SCRAPBOOK.SPECIALINFO.THURIBLE = "Canlandırılmış İskeletleri taşıyana çeker."
STRINGS.SCRAPBOOK.SPECIALINFO.TILLWEEDSALVE = "8 Can iyileştirir ve sonra 1 dakika boyunca 20 Can daha verir."
STRINGS.SCRAPBOOK.SPECIALINFO.TOADSTOOLCAP = "Kesilebilir. Devam et ve kes.\n\nLütfen kes."
STRINGS.SCRAPBOOK.SPECIALINFO.TORCH = "Tutulduğunda ışık yaratır.\n\nHedefleri ateşe verebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.TOWNPORTAL = "15 Akıl Sağlığı karşılığında, bir hayatta kalan cihazı etkinleştirebilir ve sonra etkin tuttuğu sürece dakikada 40 Akıl Sağlığı harcar. İkinci bir hayatta kalan başka bir Tembel Kaçak veya Çöl Taşı kullanarak etkin olana ışınlanabilir. Işınlanma 50 Akıl Sağlığı harcar."
STRINGS.SCRAPBOOK.SPECIALINFO.TOWNPORTALTALISMAN = "Başka bir hayatta kalan Tembel Kaçak kullanırken, ona ışınlanmak için bunu kullan."
STRINGS.SCRAPBOOK.SPECIALINFO.TRAP = "Yere yerleştirildiğinde, uygun boyuttaki yaratık yakına geldiğinde tetiklenir ve onları yakalar.\n\nYakalanan tuzağı toplama yaratığı veya ganimetin envanterine koyar.\n\nTuzaklar uygun yiyecekle yemlenir."
STRINGS.SCRAPBOOK.SPECIALINFO.TRAPTEETH = "Yere dikildikten sonra, yaratık yakına yürüdüğünde tetiklenir.\n\nTetiklendikten sonra yeniden kurulması gerekir. Alınıp taşınabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.TREASURECHEST = "9 bölmeli konteyner."
STRINGS.SCRAPBOOK.SPECIALINFO.TREE = "Ağacın yanında durmak yağmurdan %35 koruma sağlar ve hayatta kalanı az miktarda serinletir."
STRINGS.SCRAPBOOK.SPECIALINFO.TREEGROWTHSOLUTION = "Ağaçları bir aşama büyütür. Ayrıca Çiftlik Toprağına 8 Büyüme Formülü, 32 Kompost ve 8 Gübre geri verebilir.\n\nWormwood'da kullanıldığında 2 Can iyileştirir ve 32 saniye boyunca saniyede 1 Can verir."
STRINGS.SCRAPBOOK.SPECIALINFO.TREE_ROCK = "Asma kökleri, nereye dikildiklerine bağlı olarak kayalardan daha fazlasını söker."
STRINGS.SCRAPBOOK.SPECIALINFO.TRIDENT = "Okyanustan küçük gayzerlerin fışkırmasına neden olmak için çalınabilir, yaratıklara ve yapılara hasar verir."
STRINGS.SCRAPBOOK.SPECIALINFO.TROPHYSCALEFISH = "Hayatta kalanlar kaseye balık koyabilir ve ağırlığını gösterir.\n\nDolduktan sonra, sadece daha ağır balıklar teraziye girer ve daha hafif balığı dışarı atar."
STRINGS.SCRAPBOOK.SPECIALINFO.TROPHYSCALEOVERSIZEDVEGGIES = "Hayatta kalanlar sepete sebze koyabilir. Büyük boy sebzeyse, ağırlığını gösterir.\n\nDolduktan sonra, sadece daha ağır sebzeler teraziye girer ve daha hafif olanı dışarı atar."
STRINGS.SCRAPBOOK.SPECIALINFO.TUMBLEWEED = "Bunlar çölde zıplayıp yol boyunca hurda toplar.\n\nHer türlü çılgın hurda.\n\nŞaşırırsın."
STRINGS.SCRAPBOOK.SPECIALINFO.TURF = "Toprak zemine yerleştirilerek zemin türünü değiştirebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.TURFCRAFTINGSTATION = "Bu cihazın yanında durmak hayatta kalana üretebileceği yeni Zemin sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.VAULT_LOBBY_EXIT = "Ne kadar uzun baksan, atlama isteği o kadar güçlenir."
STRINGS.SCRAPBOOK.SPECIALINFO.VAULT_ORB = "Mabed İşaret Noktası için niyet odağı, ötedekiler bir araya getirir."
STRINGS.SCRAPBOOK.SPECIALINFO.VAULT_RUNE = "Kazınmış işaretler, sonsuzluk boyunca dayanır. Belki çözülebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.VAULT_TELEPORTER = "Gösterişli ulaşım. Baş dönmesi veya oryantasyon bozukluğu hissedersen bakışını yere çevir."
STRINGS.SCRAPBOOK.SPECIALINFO.VAULT_TORCH = "Alev sakinleştirici. Keşke yanık kalsa."
STRINGS.SCRAPBOOK.SPECIALINFO.VOIDCLITHSCYTHE = "Bu alet çevresindeki alanda hasat edilebilir şeyleri Biçer, sadece tek bir eşyayı değil."
STRINGS.SCRAPBOOK.SPECIALINFO.VOIDCLOTHARMOR = "Bu korkunç cübbeyi giymek etrafındaki her şeyin ne kadar korkunç olduğunu umursamamanı sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.VOIDCLOTHHAT = "Gölge Düzlemsel hasar silahlarından gelen hasar, saldırmaya devam edebilirsen ardışık vuruşlarla artar.\nVurulmak bu hasar zincirini kırar."
STRINGS.SCRAPBOOK.SPECIALINFO.VOIDCLOTHKIT = "Karanlık Paçavralarla üretilen aletlerin ve silahların dayanıklılığını geri yükler."
STRINGS.SCRAPBOOK.SPECIALINFO.VOIDCLOTHUMBRELLA = "Yerdeyken, hayatta kalanları yağmur ve yağmur benzeri etkilerden koruyan bir bariyer oluşturmak için etkinleştirilebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.VOIDCLOTH_BOOMERANG = "Üç mermi fırlatan menzilli silah, mermiler ne kadar uzağa giderse o kadar fazla hasar verir.\n\nBoşluk Başlığı kuşanmak ek bir mermi verir. Gloomerang ayrıca tutulduğunda hareket hızını %10 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGBOSS_MISSILE = "Bu ısı güdümlü füzeler bulabilecekleri en sıcak şeye kilitlenir... O şeyin sen olmadığından emin ol!"
STRINGS.SCRAPBOOK.SPECIALINFO.WAGBOSS_ROBOT_CONSTRUCTIONSITE = "W.A.R.B.O.T.'u sadece en otantik parçalarla inşa et."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGBOSS_ROBOT_CONSTRUCTIONSITE_KIT = "Bu düzeneğin gidebileceği tek bir yer var ki çevreleme bariyeri kullanılan enerjileri stabilize etmede rolünü oynayabilsin."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGBOSS_ROBOT_CREATION_PARTS = "W.A.R.B.O.T. inşaatı için doğru spesifikasyonlara göre kesilmiş parçalar."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGBOSS_ROBOT_LEG = "W.A.R.B.O.T. malzemesi Göksel Tomurcuğu tamamen çevreleyemese de, hayatta kalanları korumada hala yararlı olabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGPUNKHAT = "\"Pekala, Oldukça Güzel Zeki Sistem.\" Hesaplama için karmaşık dişli ve devre düzeneği kullanır.\n\nBir hedef seçildikten sonra, menzilde kaldığı sürece W.A.R.B.I.S. hedefle savaşmak için optimal performansı hesaplamaya başlar.\n\nBaş donanımı hedefi analiz ederken kullanıcının hasarını artırır, %20 hasar artışında son bulur.\n\nW.A.R.B.I.S. zırhıyla birleştirildiğinde, ikisi birkaç anlığına hedef bilgisini paylaşarak senkronize olur.\n\nW.A.R.B.I.S. Baş Donanımını giymek ayrıca kullanıcıya hangi hedefin analiz edildiği ve W.A.R.B.I.S.'in hangi seviyeye ulaştığı bilgisini veren Dramatik Güncellenen Diyagram (veya D.U.D.) sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_CONTAINMENT_NOTE = "\"Gün 226 - Çevreleme Önlemleri\"\n\n\"Deney öncesi çevreleme alanı gerekli. Kinetik ve teleportasyon sönümleme alanı uygulamayı düşün?\""
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_ELECTRICITY_NOTE = "\"Gün 418 - Elektrikleyici!\"\n\n\"İlginç. Kontrollü elektrik deşarjını pratik (ve saldırgan) uygulamalara yönlendirebilirim. Gerçekten olağanüstü bir potansiyel. Kendime not: bir dahaki sefere uygun yalıtkan katmanlar giy. O son çarpma... doğrusu beklediğimden daha sarsıcıydı.\""
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_ENERGY_NOTE = "\"Gün 195 - Enerji\"\n\n\"Eureka. Ay formları sınırsız enerji yayar. Çevrelenebilir. İtaatkar bile? Kontrol mümkün olabilir. Sonsuz uygulamalar... stabilite tutarsa.\""
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_MACHINERY = "Sanki biri burada çalışıyormuş gibi görünüyor. Ne yapıyorlarsa, sanırım bitirdiler."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_MATERIALS_NOTE = "\"Gün 89 - Malzeme Çalışması\"\n\n\"Thulecite ay varlıklarını çevrelemek için yeterli görünüyor. Yapısal bütünlük orta düzeyde gerilim altında dayanıyor. İleri test öneriliyor.\""
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_MUTATIONS_NOTE = "\"Gün 56 - Ay Mutasyonları Çalışması\"\n\n\"Görünüşe göre çatlaklardan çıkan bu garip varlıklar canlı konaklar arıyor... ya da belki bir zamanlar canlı olanları.\"\n\n\"NOT: Aşağıdaki yaratıklar acil çalışmayı hak ediyor çünkü konak olarak en uygun olanlar olabileceklerinden şüpheleniyorum:\"\n\n• Kurbağa\n• Pengull\n• Varg\n• Koalefant\n• Deerclops\n\n\"Diğer olası Çatlak varlığı konak adayları:\"\n\n• Çimen Gekkosu\n• Tazı\n• Bearger\n• Mosling"
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_THERMAL_NOTE = "Gün 354 - Isı İmzası Tespiti\n\nÖn termal takip işlevsel. Ancak, tepki düzensizlikleri ilkel müdahaleye karşı savunmasızlık öneriyor - minimal termal maskeleme ile yanlış pozitifler gözlemlendi."
STRINGS.SCRAPBOOK.SPECIALINFO.WAGSTAFF_TOOL = "Gizemli bir karakter tarafından statik durdurmak için kullanılan bir eşya."
STRINGS.SCRAPBOOK.SPECIALINFO.WALKINGSTICK = "Tutulduğunda hareket hızını %15 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WALLS = "Envanter duvar eşyaları kullanılarak tamir edilebilir.\n\n4 seviyeye kadar inşa edilebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WALRUSCAMP = "Kış kullanımı için tasarlanmış bir avcı kampı."
STRINGS.SCRAPBOOK.SPECIALINFO.WALTERHAT = "Walter'ın hasar nedeniyle akıl sağlığı kaybı yarıya iner."
STRINGS.SCRAPBOOK.SPECIALINFO.WANDERINGTRADER = "Birkaç İlgi Noktası arasında seyahat eder, takas yapmak için hayatta kalanları arar. Birkaç günde bir yeni stok alır, bu yüzden düzenli olarak kontrol etmeyi unutma!"
STRINGS.SCRAPBOOK.SPECIALINFO.WARDROBE = "Bir hayatta kalan toplanan görünümlerle kıyafetini ekleyebilir, çıkarabilir ve değiştirebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WATERBALLOON = "Fırlatıldığında düştüğü küçük alanda yangınları söndürür.\n\nAyrıca hedefleri 5 derece soğutur ve 20 nemlilik ekler."
STRINGS.SCRAPBOOK.SPECIALINFO.WATERINGCAN = "Kullanım başına Bahçe Toprağına 25 nemlilik puanı ekler.\n\nAyrıca yangınları söndürebilir ve için için yanmayı durdurabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WATERMELONHAT = "Taşıyıcının nemliliği yavaşça %33'e kadar yükselir"
STRINGS.SCRAPBOOK.SPECIALINFO.WATERPUMP = "Bir tekneye yerleştirildiğinde, okyanustan su çekmek için manuel olarak çalıştırılabilir ve yakındaki yangınlara ve için için yanan eşyalara püskürtebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WATERTREEPILLAR = "Bu ağaç altındaki alanı gölgeleyen büyük bir yaprak örtüsüne sahiptir ve yağmurdan %35 koruma sağlar ve hayatta kalanı az miktarda serinletir."
STRINGS.SCRAPBOOK.SPECIALINFO.WATHGRITHR_SHIELD = "Saldırıları engellemek için kullanılabilir. Başarılı bir engelleme blok bekleme süresini azaltır.\n\nSadece \"Savaş Rönd\" becerisine sahip Wigfrid'ler tarafından kuşanılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WILLOWEMBER = "Bir yaratık yanarak öldüğünde, yanmış yaşam özünün eterik bir közünü düşürür.\n\nWillow çakmağıyla uyum sağladığında, sonunda Sıcak Közleri hissedebilir ve onunla toplayabilir.\n\nWillow közleri çeşitli Pirokinetik için kullanmayı öğrenebilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WINCH = "Bir tekneye inşa edildiğinde, pençesi suyun derinliklerindeki nesneleri yakalamak için suya indirilebilir. Yakalayacak bir şey bulursa, onu tekneye çeker."
STRINGS.SCRAPBOOK.SPECIALINFO.WINONABATTERYHIGH = "Mücevherler güç sahibi olmak için yuvasına yerleştirilmelidir. Yerleştirilen her mücevher toplam şarjın 1/3'ünü ekler.\n\nTamamen şarj olduğunda bir cihazı 6 gün çalıştıracak güce sahiptir."
STRINGS.SCRAPBOOK.SPECIALINFO.WINONABATTERYLOW = "Tamamen şarj olduğunda, bir cihazı 1 gün çalıştıracak güce sahiptir."
STRINGS.SCRAPBOOK.SPECIALINFO.WINONACATAPULT = "Çalışması için yakındaki bir Jeneratör veya G.E.M.eratör tarafından güçlendirilmelidir.\n\nGüçlendirildiğinde, menzildeki düşman yaratıkları otomatik olarak saldırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WINONASPOTLIGHT = "Güçlendirildiğinde, en yakın hayatta kalana spot ışığı tutar.\n\nBirden fazla spot ışığı ve yakında birden fazla hayatta kalan varsa, farklı hedeflere öncelik verirler."
STRINGS.SCRAPBOOK.SPECIALINFO.WINTEROMETOR = "Bu cihaz 0 ile 35 derece arasındaki mevcut sıcaklığı söyler.\n\nKış sırasında maviye döner."
STRINGS.SCRAPBOOK.SPECIALINFO.WINTERSFEASTCOOKEDFOODS = "Kış Şöleni Masasına konulduğunda yemeğin ruhunu yakalar. Ne kadar çok o kadar neşeli."
STRINGS.SCRAPBOOK.SPECIALINFO.WINTERSFEASTOVEN = "Bu cihazın yakınında durmak hayatta kalana bu fırında pişirmeye başlayabilecekleri \"Kış Şöleni yemeği\" özel üretim seçenekleri sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.WINTERTREE_ORNAMENT = "Şenlik Ağacı Saksısında yetiştirilen özel ağaçlara asılabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WOBY_TREAT = "Woby tarafından yenildiğinde üç kat daha fazla açlık giderir."
STRINGS.SCRAPBOOK.SPECIALINFO.WOLFGANG_WHISTLE = "Wolfgang'ın koçluk becerisini açıp kapatır."
STRINGS.SCRAPBOOK.SPECIALINFO.WOODCARVEDHAT = "Depremler sırasında giyeni düşen molozdan korur."
STRINGS.SCRAPBOOK.SPECIALINFO.WORMHOLE = "Bu deliğe atlamak 15 Akıl puanına mal olur.\n\nNereden çıkacak?"
STRINGS.SCRAPBOOK.SPECIALINFO.WORM_BOSS = "Derinlik Solucanının atası hareket halindeyken saldırmak için tehlikelidir."
STRINGS.SCRAPBOOK.SPECIALINFO.WORTOX_SOUL = "Wortox bunları yiyerek 25 Açlık giderebilir ve 5 Akıl kaybeder.\n\nYakındaki tüm hayatta kalanları iyileştirmek için serbest bırakılabilir, maksimum iyileşme 20 can olup her ek hayatta kalan için 2 puan düşerek minimum 5 cana iner.\n\nAyrıca Ruh Zıplaması için Ruh harcayarak ışınlanabilir.\n\nEğer Wortox 20'den fazla Ruh tutarsa, yarısını serbest bırakır ve 20 Akıl kaybeder."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULEREMOVER = "WX-78'den takılı Devreleri çıkarır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_BEE = "WX78'in devre kartına takılır.\n\n3 soket gerektirir, her 30 saniyede 5 Can iyileştirir, dakikada 2 Akıl Sağlığı kazandırır ve Maksimum Akıl Sağlığını 100 puan artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_COLD = "WX78'in devre kartına takılır.\n\n3 soket gerektirir, vücut sıcaklığını 20 derece düşürür ve envanter bozulma oranını %25 azaltır. Yakındaki hayatta kalanları da soğutur.\n\nEğer WX78'in ıslaklığı %95'e ulaşırsa, %0'a düşer ve 2 Buz oluşur."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_HEAT = "WX78'in devre kartına takılır.\n\n3 soket gerektirir, vücut sıcaklığını 20 derece yükseltir, envanter bozulma oranını %25 artırır ve kuruma oranını %10 artırır. Yakındaki hayatta kalanları da ısıtır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_LIGHT = "WX78'in devre kartına takılır.\n\n3 soket gerektirir ve ışık yaratır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MAXHEALTH = "WX78'in devre kartına takılır.\n\n1 soket gerektirir ve Maksimum Canı +50 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MAXHEALTH2 = "WX78'in devre kartına takılır.\n\n2 soket gerektirir ve Maksimum Canı 150 puan artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MAXHUNGER = "WX78'in devre kartına takılır.\n\n2 soket gerektirir, Maksimum Açlığı 100 puan artırır ve Açlık azalmasını %20 azaltır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MAXHUNGER1 = "WX78'in devre kartına takılır.\n\n1 soket gerektirir ve Maksimum Açlığı 40 puan artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MAXSANITY = "WX78'in devre kartına takılır.\n\n2 soket gerektirir ve Maksimum Akıl Sağlığını +100 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MAXSANITY1 = "WX78'in devre kartına takılır.\n\n1 soket gerektirir ve Maksimum Akıl Sağlığını +40 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MOVESPEED = "WX78'in devre kartına takılır.\n\n6 soket gerektirir ve hareket hızını %25 artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MOVESPEED2 = "WX78'in devre kartına takılır.\n\n2 soket gerektirir.\nİlki hareket hızını %25 artırır.\nİkincisi hareket hızını %15 artırır.\nÜçüncüsü hareket hızını %10 artırır.\nBöylece maksimum hız artışı %50 olabilir."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_MUSIC = "WX78'in devre kartına takılır.\n\n3 soket gerektirir, yakındaki hayatta kalanların Akıl Sağlığını dakikada 5 puan artırır ve bahçe bitkilerinin mutluluğunu bir adım artırır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_NIGHTVISION = "WX78'in devre kartına takılır.\n\n4 soket gerektirir ve kullanıcının karanlıkta görmesini sağlar. Geceleri ve Mağaralara girerken açılır."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78MODULE_TASER = "WX78'in devre kartına takılır.\n\n2 soket gerektirir ve WX78'e saldıranlara 20 elektriksel hasar verir.\n\nBu modül ayrıca WX78'i elektriksel hasara karşı bağışık yapar."
STRINGS.SCRAPBOOK.SPECIALINFO.WX78SCANNER = "Yakında ilginç biyolojik hedefler olduğunda cıvıldar.\n\nWX-78 yakınken ilginç biyolojik hedefleri kovalayıp tarar.\n\nBittiğinde Bio Veri düşürür."
STRINGS.SCRAPBOOK.SPECIALINFO.YELLOWAMULET = "Meşale gibi ışık yayar ve takılıyken %20 hız artışı sağlar."
STRINGS.SCRAPBOOK.SPECIALINFO.YELLOWSTAFF = "Cüce Yıldızı yaratır."
