STRINGS.SKILLTREE.WALTER.WALTER_AMMO_BAG_DESC = "Fazla mühimmatınızı taşımak için Mühimmat Kesesi nasıl yapılacağını öğrenin."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_BAG_TITLE = "Mühimmat İstifçisi"
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_EFFICIENCY_DESC = "Daha iyi verim için mühimmatı daha hızlı ve verimli nasıl yapacağınızı öğrenin."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_EFFICIENCY_TITLE = "Mühimmat Ustası"
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_LOCK_DESC = "Kilidini açmak için 2 Mühimmat yeteneği öğrenin."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_LUCKY_DESC = "Kablooie ve Korku Çakıltaşı nasıl yapılacağını öğrenin. Bu mühimmat türleri daha fazla hasar vermek veya kırılmamak için şanslı atışlara dayanır."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_LUCKY_TITLE = "Şanslı Mermiler"
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_LUNAR_DESC = "Gizemli Kurucu merakınızı ödüllendirecek ve size Saf Parlaklık ve Parlak Gölge Kabuk Mermilerini nasıl yapacağınızı öğretecek: sırasıyla zayıflatma ve hasar odaklı mühimmat."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_LUNAR_LOCK_DESC = "Göksel Şampiyonu bul ve yen, açılacak Gölge Bağlılık Yeteneğin kalmasın."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_LUNAR_TITLE = "Ay Sapancısı"
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_SHADOW_DESC = "Kraliçe sadakatini ödüllendirip sana Icky ile Saf Dehşet Mermileri yapmayı öğretecek: biri yavaşlatmaya, diğeri hasara odaklı."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_SHADOW_LOCK_DESC = "Kadim Yakıt Dokuyucuyu bul ve yen, açılacak Ay Bağlılık Yeteneğin kalmasın."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_SHADOW_TITLE = "Gölge Sapancısı"
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_SHATTERSHOTS_DESC = "Iğne Zıngırdakları ve Ay Atışlarını nasıl yapacağını öğren. Bu mühimmat türleri parçalanarak alan hasarı verir."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_SHATTERSHOTS_TITLE = "Parçalayan Mermiler"
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_UTILITY_DESC = "Yapışkanları ve Şok Hurda Atışlarını nasıl yapacağını öğren. Yapışkanlar vurulan hedefleri yavaşlatır, Şok Hurda Atışları daha yüksek sersemletme oranıyla elektrik hasarı verir."
STRINGS.SKILLTREE.WALTER.WALTER_AMMO_UTILITY_TITLE = "Faydalı Mermiler"
