STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_THEM = "\"Onlardan sonsuza dek kaçamazsın. Benden bil, dostum.\" -M"
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_TIME = "Zaman Constant'ta farklı akar. Burada saniyelerle sonsuzluklar, tekdüze ilerlemek yerine istedikleri gibi ileri geri savruluyor gibidir."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WALTER = "Walter'ın Çam Ağacı Öncüleri'ndeki zamanı onu vahşi doğada hayatta kalmak için çoğundan daha hazırlıklı hale getirdi. Ne yazık ki, bu canavarlarla olan kör büyülenişi tarafından biraz baltalanıyor."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WARNING = "\"Burada hiçbir şey göründüğü gibi değil. Bunu okuyorsan, tavşanları gözle, heykellere güvenme ve gece gökyüzünde asılı duran o şeyi ay sanma...\" -W"
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WEBBER = "Bir zamanlar küçük bir çocuk büyük aç bir örümcek tarafından bütünüyle yutulmuştu. Şimdi her şeyi paylaşıyorlar; bir vücut, bir zihin ve Webber adını."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WENDY = "Wendy ile ikiz kız kardeşi Abigail arasına hiçbir şey giremezdi. Bazı bağlar ölümü bile aşar."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WICKERBOTTOM = "Wickerbottom kalemin kılıçtan daha güçlü olduğuna kesinlikle inanır. Doğru kullanıldığında kelimeler büyük güç taşır."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WILLOW = "Willow'u sadık oyuncak ayısı Bernie'ye sarılmak ve şakacı bir kundaklama yapmaktan daha çok rahatlatan hiçbir şey yoktur."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WILSON_UNI = "Wilson, üniversite ortamını hırsları olan bir adam için çok boğucu bulduğu için bağımsız Centilmen Bilim İnsanı yolunu seçti. (Üniversitenin kimya laboratuvarındaki onarımlar için gönderdiği devasa faturanın bununla kesinlikle hiçbir alakası yoktu.)"
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WINONA_CHARLIE = "Büyürken Winona her zaman küçük kız kardeşine göz kulak olurdu. Şimdi bile, bir gün karanlığa uzanıp Charlie'yi geri çekebileceğini hissetmekten kendini alamıyor."
STRINGS.UI.LOADING_SCREEN_LORE_TIPS.TIP_WOODIE = "Woodie were-lanetini kontrol etmek için attığı tüm adımlara rağmen, ayın en dolgun olduğu gecelerde yapılabilecek çok az şey var."
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS = STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS or {}
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_BERRYLURE = "\"Geçen sefer oltamı meyvelerle yemledim ve taşıyamayacağım kadar balık yakaladım, ama bugün denediğimde? Zar zor bir ısırık! Sanırım meyve hilesi sadece bazılarında işe yarıyor.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_BOTTLES = "\"Zaman zaman okyanus akıntıları boyunca yüzen şişeler gördüm, kıyıdan ulaşılamayacak kadar uzakta. Bir tekne yapıp birini almaya yarı aklım var... İçimde birinin mesaj göndermeye çalıştığı hissi var.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_CAVES = "\"Sonunda yeraltı mağaralarını keşfetme cesaretini topladım. Şaşırtıcı bir şekilde, mağara sistemi boyunca doğal olarak büyüyen çok tuhaf ışıldayan bir bitkinin bol ışık sağladığını gördüm. Daha fazla çalışma için bazı soğanlar topladım.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_CHARCOAL = "\"Bilirsin işte, birkaç ağaç yakmadan mangal kömürü elde edemezsin!\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_COBBLEDROAD = "\"Bugün taş döşeli bir yola rastladığımda şaşırdım - medeniyetin bu alameti bu ehlileşmemiş vahşi doğada nasıl ortaya çıktı?\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_COMPASS = "\"İlkel bir pusula yapmayı denedim ve bu yerin gerçekten manyetik bir Kuzeyi olduğunu keşfettim. Tuhaf bir şekilde, kendi benzer pusulalarını çoktan yapmış olan kamp arkadaşlarımın pozisyonlarını da gösterdi.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_COOKBOOK = "\"Bir tarifi mükemmelleştirdikten sonra, onu yazmayı faydalı buluyorum. Neyse ki, bazı parşömen parçalarından böyle bir şey için kabataslak bir yemek kitabı yapabildim. Şimdi aklım daha acil şeyler için özgür...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_DARKNESS = "\"Gölge Kraliçesi'nin geceleri karanlıkta dolaşacak kadar aptal olanları kapmaya geldiğini söylüyorlar...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_DIRT_PILE = "\"Oldukça şüpheli bir toprak yığınına rastladım... belki bir tür yaratık tarafından bırakılmıştı? Bu daha fazla araştırma gerektirebilir...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_FLARE = "\"Dün gece ormandan bir işaret fişeği gönderildi. Hemen yardıma gitmeliydim ama... şey... sanırım kamp ateşimin rahatlatıcı ışığı yanında çok uzun tereddüt ettim ve fark etmeden işaret fişeği gözden kayboldu. Umarım her kimse iyidir...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_GARDENEERHAT = "\"Sonunda önemli bahçe bilgilerini saklayan dahiyane (kendim söylüyorum) cihazımın tasarımını mükemmelleştirdim. Bazı karşı çıkanlar bunun kafada takılan ters çevrilmiş saksıdan başka bir şeye benzemediğini söyleyebilir... bazı insanların bilim gözü yok.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_HEAT = "\"Kahrolası bu sıcak! İhtiyacın olduğunda güzel, soğuk bir içecek nerede?\" -M"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_MERMHOUSE = "\"Mermler şiddetle bölgeseldir ve evlerini savunmaya hazırdır. Gerçi kimsenin o harap kulübelerde oturmak isteyeceğini hayal edemiyorum...\" -M"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_MOONISLAND = "\"Hayal etmiş olamam, ayın bir parçasının kopup okyanusa düştüğünü gördüğümden eminim! Belki yoldaşlarım onu aramada bana katılır...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_MOONMUTATION = "\"Bu dünyadaki ay buradaki yaratıklar üzerinde garip bir güce sahip görünüyor. Onları değiştiriyor...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_NAUGHTINESS = "\"Bize zarar vermeyen şeylere zarar vermemeliyiz. Eğer kötü olursak, yaşlı kötü Bay Krampus gelir...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_NEWRECIPES = "\"Tarifler faydalıdır, ama gerçek bir aşçı yeni malzemeler ve tatlarla deneyim yapmanın önemini bilir ve bu dünya kesinlikle seçim yapabileceğin bol miktarda alışılmadık şey sağlıyor.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_OCEANEXPLORATION = "\"Denize açılırsam ne garip yeni adalar ve yaratıklarla karşılaşabilirim? Düşünmekten ürperiyorum... ama merak bende üstün gelme eğiliminde...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_PIG_AND_MONSTERS = "\"Domuz adamlar Constant'ın daha canavarımsı sakinlerine karşı derin bir antipatiye sahip görünüyor, onları görür görmez saldırıyorlar. Şahsen onları suçlayamasam da, bazı yoldaşlarım için biraz sorun teşkil ediyor...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_REPLANTING = "\"Kampın yanına diktiğim çalılar hastalıklı görünüyor... tekrar meyve verebilmeleri için ekstra bakıma ihtiyaç duyacaklarından şüpheleniyorum.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_REVIVE = "\"Bugün sayımızdan birini neredeyse kaybediyorduk. Çılgın bir sersemlikle... bir şey... yarattım ve arkadaşımızı yaşayanlar diyarına geri çekmeyi başardı, ama... her ne idiyse, bunun bilim alanında olduğunu haklı olarak söyleyebileceğimden korkuyorum...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_RUN_AWAY = "\"Koalefant'ların beklediğimden biraz daha dayanıklı olduğu ortaya çıktı. (oldukça mantıklı bir şekilde) daha iyi hazırlanana kadar... stratejik bir geri çekilme yapmaya karar verdim.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_SANITY = "\"Artık kendi gözlerime güvenemeyeceğimden korkuyorum. Görüş alanımın kenarlarında garip gölgeli şekillerin görüntülerini giderek artan sıklıkta yakalıyorum... kesinlikle gerçekten orada olamazlar?\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_SCIENCE_MACHINE = "\"Kendimi muhteşem bilim makineme giderek daha sık dönerken buluyorum, hayatta kalmamıza yardımcı olacak yeni aletlerin prototiplerini yapmakla meşgul oluyorum. Sonuçta, bu garip yerde aklımı başımda tutmak için bir şeyler yapmalıyım...\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_TREEGUARD = "\"Yakacak odun kesmeye gittiğimde ağaçlardan birinin hareket ettiğini gördüğüme yemin edebilirdim... ışığın bir oyunu olmalı.\" -W"
STRINGS.UI.LOADING_SCREEN_SURVIVAL_TIPS.TIP_WETNESS = "\"Yağmur ilk tahmin ettiğimden daha büyük bir engel olduğunu kanıtlıyor. Kemiklerime kadar ıslanmak yeterince korkunç değilmiş gibi, aletlerimi kullanmaya çalıştığımda ellerimden kayıp duruyor!\" -W"
